import { colors, fonts } from "../../styles/theme";

// ─── MEDITATION ILLUSTRATION ──────────────────────────────────────────────────
export const MeditationSVG = ({ size = 320 }) => (
  <img
    src="/hero-image.png"
    alt="Mental wellness illustration"
    style={{
      width: size,
      height: size,
      objectFit: "contain",
      // borderRadius: "50%",
      flexShrink: 0,
    }}
  />
);

// ─── LOGO ─────────────────────────────────────────────────────────────────────
export const Logo = ({ size = "md", dark = false }) => {
  return (
    <img
      src="/logo.png"
      alt="CalmMind Logo"
      style={{
        height: size === "sm" ? 36 : 48,
        width: "auto",
        objectFit: "contain",
        filter: dark ? "brightness(0) invert(1)" : "none",
      }}
    />
  );
};
